<?phpclass record {		public $fc;	public $cc;	public $label;	public $insertID;	public $prefix;	public $issue;	public $title;	public $alt_num;	public $performers;	public $director;	public $solo;	public $date;		public function showRecord(){						echo '<h1>Insert Chant</h1>		  <input id="record_id" type="hidden" value="'. $this->insertID.'" /><label>Item Num:</label><input id="item_num" type="text" tabindex="1" size="2" maxlength="2" /><br /><label>Track Num:</label> <input id="track_num" type="text" tabindex="2" size="5" maxlength="5" /> <br /> <label>Title of Chant:</label> <input id="title_of_chant" type="text" tabindex="3" size="50" maxlength="150" /> <br /> <label>Page:</label> <input id="page" type="text" tabindex="6" size="50" maxlength="150" /> <br /> <label>Time:</label> <input id="time" type="text" tabindex="8" size="35" maxlength="5" /> <br /> <label>Comments:</label> <textarea cols="35" rows="5" id="comments" tabindex="9"></textarea>';		}		public function showTracks(){		echo "<b> $this->fc = $this->cc = $this->label $this->prefix $this->issue <br>		Title:</b>  $this->title <br>		<b>Also issued as</b> $this->alt_num <br>		<b>Performer</b>  $this->performers <br>		<b>Director</b>  $this->director <br>		<b>Solo</b>  $this->solo <br>		<b>Date:</b>  $this->date";		//echo "<div>TRACNKS GO HERE</div>";	}}?>